local LBattleShowSkillData = classX("LBattleShowSkillData", nil)

function LBattleShowSkillData:ctor()
    self.dataName = nil
    self.skillAsset = nil
    self.skillJson = nil
    
    self.castEffect = {}
    self.eventEffect = {}
    self.hitEffect = {}
    self.moveToEffect = {}
    self.moveBackEffect = {}

    self.isModelData = false
    self.modelEffect = {}
    self.modelHudOffsetX = 0
    self.modelHudOffsetY = BattleHudHeight
    self.modelHudOffsetZ = 0

    -- 从hitEffect中抽取出来
    self.textEffect = {}

    self.castPos = BattleShowCastPosType.Stand
    self.moveTime = 0.18
    self.eventTime = 0.5
    self.backTime = 0.1
    self.stopTime = 0.1
    self.aniName = "attack1"
    self.testTarget = BattleShowTestTargetType.Enemy2
    self.isHurtText = false

    self._isLoading = false
    self._isLoaded = false
    self._loadCallbacks = {}
    self._isInitOk = false
end
function LBattleShowSkillData:Dispose()
    if self.skillAsset ~= nil then
        self.skillAsset:Dispose()
        self.skillAsset = nil
    end
end
---@param dataName string 格式必须是类似 Taolexi_skill1
function LBattleShowSkillData:LoadSkillData(dataName, callback, bForce)
    local strList = string.split(dataName, '_')
    if #strList ~= 3 then
        if callback then
            callback(self)
        end
        if LOG_INFO_ENABLED then
            ShowSysMsg("技能显示Id格式错误: id="..dataName)
        end
        return
    end

    if self._isLoaded and not bForce then
        if callback then
            callback(self)
        end
        return
    end

    self.dataName = dataName
    table.insert(self._loadCallbacks, callback)
    self.isModelData = false
    if string.endswith(self.dataName, 'idle') then
        self.isModelData = true
    end

    if not self._isLoading then
        self._isLoading = true
        local fileNames = {}
        for i = 1,#strList - 1 do
            table.insert(fileNames, strList[i])
        end
        local fileNameStr = table.concat(fileNames, "_")
        local assetPath = 'Spine/' .. fileNameStr.."/"..dataName..".json"
        self.skillAsset = require("LApp.component.res.LJsonAsset"):new()
        self.skillAsset:InitAsset(assetPath)
        self.skillAsset:SetLoadedCallback(function(asset)
            self:OnSkillDataLoad(asset)
            if self.skillAsset ~= nil then
                self.skillAsset:Dispose()
                self.skillAsset = nil
            end
        end)
        self.skillAsset:Load()
    end

end

---只能在编辑器使用这个方法
function LBattleShowSkillData:SaveSkillData()
    local filePath = nil
    local dataName = self.dataName
    local saveSpinePath = CtrlCenter.Battle:GetSpineSkillSavePath(dataName)
    if not saveSpinePath then
        if LOG_INFO_ENABLED then
            LogError("dataName = "..dataName.." 不符合规范！命名格式( XR_模型名_动作名 )")
        end
        return
    end

    filePath = saveSpinePath..'/'..dataName..".json"
    self._isInitOk = true
    local skillData = {}

    if self.isModelData then
        skillData.aniName = self.aniName
        skillData.modelHudOffsetX = self.modelHudOffsetX
        skillData.modelHudOffsetY = self.modelHudOffsetY
        skillData.modelHudOffsetZ = self.modelHudOffsetZ
        table.sort(self.modelEffect, function(a, b) return a.name < b.name end)
        skillData.modelEffect = self.modelEffect
    else
        skillData.dataName = self.dataName
        skillData.castPos = self.castPos
        skillData.aniName = self.aniName
        skillData.eventTime = self.eventTime
        skillData.moveTime = self.moveTime or 0.18
        skillData.testTarget = self.testTarget
        skillData.backTime = self.backTime or 0.1
        skillData.stopTime = self.stopTime or 0.1

        table.sort(self.castEffect, function(a, b) return a.name < b.name end)
        table.sort(self.eventEffect, function(a, b) return a.name < b.name end)
        table.sort(self.hitEffect, function(a, b) return a.name < b.name end)
        table.sort(self.moveToEffect, function(a, b) return a.name < b.name end)
        table.sort(self.moveBackEffect, function(a, b) return a.name < b.name end)

        skillData.castEffect = self.castEffect
        skillData.eventEffect = self.eventEffect
        skillData.hitEffect = self.hitEffect
        skillData.moveToEffect = self.moveToEffect
        skillData.moveBackEffect = self.moveBackEffect
    end

    local jsonStr = CJSON.encode(skillData)
    local savePath = UnityEngine.Application.dataPath .."/Res/"..filePath
    LFileHelper.WriteAllText(savePath, jsonStr, false)
end

function LBattleShowSkillData:OnSkillDataLoad(asset)
    self._isLoading = false
    self._isLoaded = true
    local jsonStr = asset:GetAsset()
    if jsonStr then
        self.skillJson = CJSON.decode(tostring(jsonStr))
        if self.isModelData then
            self:InitModelData(self.skillJson)
        else
            self:InitSkillData(self.skillJson)
        end

    end

    if self._loadCallbacks and #self._loadCallbacks > 0 then
        local loadCallbacks = self._loadCallbacks
        self._loadCallbacks = {}
        for i, callback in ipairs(loadCallbacks) do
            callback(self)
        end
    end
end
function LBattleShowSkillData:IsInitOk()
    return self._isInitOk
end
function LBattleShowSkillData:InitModelData(skillJson)
    if not skillJson then
        return
    end
    self._isInitOk = true
    self.aniName = skillJson.aniName
    self.modelEffect = {}
    self.modelHudOffsetX = tonumber(skillJson.modelHudOffsetX) or 0
    self.modelHudOffsetY = tonumber(skillJson.modelHudOffsetY) or BattleHudHeight
    self.modelHudOffsetZ = tonumber(skillJson.modelHudOffsetZ) or 0
    if skillJson.modelEffect then
        for i, v in ipairs(skillJson.modelEffect) do
            table.insert(self.modelEffect, v)
        end
    end
end
function LBattleShowSkillData:InitSkillData(skillJson)
    if not skillJson then
        return
    end
    self._isInitOk = true
    if string.isempty(self.dataName) then
        self.dataName = skillJson.dataName
    end
    self.castPos = skillJson.castPos
    self.aniName = skillJson.aniName
    self.testTarget = skillJson.testTarget
    self.eventTime = tonumber(skillJson.eventTime) or 0.5
    self.moveTime = tonumber(skillJson.moveTime) or 0.18
    self.backTime = tonumber(skillJson.backTime) or 0.1
    self.stopTime = tonumber(skillJson.stopTime) or 0.1
    self.castEffect = {}
    self.eventEffect = {}
    self.hitEffect = {}
    self.moveToEffect = {}
    self.moveBackEffect = {}
    self.textEffect = {}

    if skillJson.castEffect then
        for i, v in ipairs(skillJson.castEffect) do
            table.insert(self.castEffect, v)
        end
    end

    if skillJson.eventEffect then
        for i, v in ipairs(skillJson.eventEffect) do
            table.insert(self.eventEffect, v)
        end
    end

    if skillJson.hitEffect then
        for i, v in ipairs(skillJson.hitEffect) do
            table.insert(self.hitEffect, v)
            if v.effectType == BattleShowEffectType.HurtText then
                self.isHurtText = true
                table.insert(self.textEffect, v)
            end
        end
    end

    if skillJson.moveToEffect then
        for i, v in ipairs(skillJson.moveToEffect) do
            table.insert(self.moveToEffect, v)
        end
    end

    if skillJson.moveBackEffect then
        for i, v in ipairs(skillJson.moveBackEffect) do
            table.insert(self.moveBackEffect, v)
        end
    end
end

function LBattleShowSkillData:GetAllEffectList()
    local effectList = {}
    if self.castEffect then
        table.sort(self.castEffect, function(a, b) return a.name < b.name end)
        for i, v in ipairs(self.castEffect) do
            table.insert(effectList, v)
        end
    end
    if self.eventEffect then
        table.sort(self.eventEffect, function(a, b) return a.name < b.name end)
        for i, v in ipairs(self.eventEffect) do
            table.insert(effectList, v)
        end
    end
    if self.hitEffect then
        table.sort(self.hitEffect, function(a, b) return a.name < b.name end)
        for i, v in ipairs(self.hitEffect) do
            table.insert(effectList, v)
        end
    end

    if self.moveToEffect then
        table.sort(self.moveToEffect, function(a, b) return a.name < b.name end)
        for i, v in ipairs(self.moveToEffect) do
            table.insert(effectList, v)
        end
    end

    if self.moveBackEffect then
        table.sort(self.moveBackEffect, function(a, b) return a.name < b.name end)
        for i, v in ipairs(self.moveBackEffect) do
            table.insert(effectList, v)
        end
    end

    return effectList
end

function LBattleShowSkillData:GetEffectList(castType)
    local effectList = nil
    if castType == BattleShowCastType.Cast then
        effectList = self.castEffect or {}
        self.castEffect = effectList
    elseif castType == BattleShowCastType.Event then
        effectList = self.eventEffect or {}
        self.eventEffect = effectList
    elseif castType == BattleShowCastType.Hit then
        effectList = self.hitEffect or {}
        self.hitEffect = effectList
    elseif castType == BattleShowCastType.MoveTo then
        effectList = self.moveToEffect or {}
        self.moveToEffect = effectList
    elseif castType == BattleShowCastType.GoBack then
        effectList = self.moveBackEffect or {}
        self.moveBackEffect = effectList
    end
    return effectList
end

function LBattleShowSkillData:RemoveModelEffectItem(effectItem)
    if not effectItem then
        return
    end
    local name = effectItem.name
    local modelEffect = self.modelEffect or {}
    local idx = 0
    for i, v in ipairs(modelEffect) do
        if v.name == name then
            idx = i
            break
        end
    end
    if idx > 0 then
        table.remove(modelEffect, idx)
    end
end
