    ---@type LBattleModelEffectItem
    local item = {
        name = "特效-"..tostring(idx),
        prefabName = '',
        hookName = BattleShowHookNodeEnum.None,
        hookOffsetX = 0,
        hookOffsetY = 0,
        hookOffsetZ = 0,
        hookRotateX = 0,
        hookRotateY = 0,
        hookRotateZ = 0,
        scale = 1
    }
    table.insert(modelEffect, item)
    return item
end
