function LBattleShowSkillData:NewItemData(nameKey, castType, effectType)
    local effectList = self:GetEffectList(castType)
    local isHasMain = false
    for i, v in ipairs(effectList) do
        if v.mainEffect == 1 then
            isHasMain = true
            break
        end
    end
    local index = #effectList + 1
    local name = nameKey.."-"..string.sub(castType, 1,1)..index
    local effectItem = {name = name, castType = castType, effectType = effectType, targetType = BattleShowTargetType.Auto, mainEffect = 0}
    if effectType == BattleShowEffectType.Effect then
         self:InitEffectData(effectItem)
    elseif effectType == BattleShowEffectType.Bullet then
        if castType ~= BattleShowCastType.Event then
            ShowSysMsg('子弹特效建议在事件阶段添加')
        end
        if not isHasMain then
            effectItem.mainEffect = 1
        end
        self:InitBulletData(effectItem)
    elseif effectType == BattleShowEffectType.Shock then
        self:InitShockData(effectItem)
    elseif effectType == BattleShowEffectType.HurtText then
        if castType ~= BattleShowCastType.Hit then
            ShowSysMsg('飘血效果建议在打击阶段添加')
        end
        self.isHurtText = true
        self:InitHurtData(effectItem)
        table.insert(self.textEffect, effectItem)
    elseif effectType == BattleShowEffectType.Face then
        self:InitFaceEffectData(effectItem)
    elseif effectType == BattleShowEffectType.Ani then
        self:InitAniEffectData(effectItem)
    elseif effectType == BattleShowEffectType.Move then
        if castType == BattleShowCastType.MoveTo or castType == BattleShowCastType.GoBack then
            if not isHasMain then
                effectItem.mainEffect = 1
            end
        end
        self:InitMoveEffectData(effectItem)
    end
    table.insert(effectList, effectItem)
    return effectItem
end

