    local effectType  = effectItem.effectType
    local name = effectItem.name
    local effectList = self:GetEffectList(castType)
    local idx = 0
    for i, v in ipairs(effectList) do
        if v.name == name then
            idx = i
            break
        end
    end
    if idx > 0 then
        table.remove(effectList, idx)
    end

    if castType == BattleShowCastType.Event then

    elseif castType == BattleShowCastType.Hit then
        self.isHurtText = false
        self.textEffect = {}
        for i, v in ipairs(effectList) do
            if v.effectType == BattleShowEffectType.HurtText then
                self.isHurtText = true
                table.insert(self.textEffect, v)
            end
        end
    elseif castType == BattleShowCastType.Cast then

    end
end
